def compute(inputs):
    cash_flows = inputs.get("cash_flows")
    discount_rate = inputs.get("discount_rate")
    initial_investment = inputs.get("initial_investment", 0.0)

    npv = -initial_investment
    for t, cash_flow in enumerate(cash_flows):
        npv += cash_flow / ((1 + discount_rate) ** (t + 1))

    return round(npv)

def compute(inputs):
    current_market_value = inputs.get("current_market_value")
    original_investment_value = inputs.get("original_investment_value")

    if original_investment_value is None or current_market_value is None:
        raise ValueError("Missing required input values.")

    if original_investment_value <= 0:
        raise ValueError("Original investment value must be greater than zero.")

    rate_of_return = (current_market_value - original_investment_value) / original_investment_value
    nominal_rate_of_return = rate_of_return * 100

    return round(nominal_rate_of_return, 2)

def compute(inputs):
    birth_year = inputs["birth_year"]

    if birth_year < 1943:
        raise ValueError("This function is applicable only for birth years 1943 and later.")

    if birth_year >= 1960:
        return 67

    if birth_year < 1955:
        return 66

    # Incremental increase for birth years 1955 to 1959
    # The result is truncated to whole years due to integer division
    return 66 + (birth_year - 1954) * 2 // 12

def compute(inputs):
    nominal_return = inputs.get("nominal_return")
    inflation_rate = inputs.get("inflation_rate")
    real_return = ((1 + nominal_return / 100) / (1 + inflation_rate / 100) - 1) * 100
    return {"real_return": real_return}

def compute(inputs):
    pd = inputs["pd"]
    lgd = inputs["lgd"]
    ead = inputs["ead"]

    if not (0 <= pd <= 1):
        raise ValueError("Probability of Default (pd) must be between 0 and 1.")
    if not (0 <= lgd <= 1):
        raise ValueError("Loss Given Default (lgd) must be between 0 and 1.")
    if ead < 0:
        raise ValueError("Exposure at Default (ead) must be non-negative.")

    rwa = pd * lgd * ead

